angular.module('jgappApp')
    .controller('ManageChooseinfoCtrl', function($scope, $rootScope, $routeParams, Util, openApi, localStorageService, PagingService) {
        var relModuleObj;
        // 获取搜索所需参数以及标题信息
        relModuleObj = Util.getDataforsearch();
        $scope.picker = angular.extend($scope.picker || {}, relModuleObj.param || {});
        $scope.picker.callback = function(data) {
            $scope.selectLists.forEach(function(item, index) {
                data.forEach(function(subitem, index) {
                    // 设置选中状态
                    if (item.uid == subitem.uid) {
                        subitem.selected = true;
                    }
                });
            })
        };
        $scope.selectLists = []; //已经选择了的数组，用来回传
        // -----------------底部款项类型选框添加end-----------------------
        $scope.choosePeople = function(item) {
            $scope.searchInput = "";
            item.selected = !item.selected;
            if (item.selected) {
                $scope.selectLists.push(item)
            } else {
                $scope.selectLists = $scope.selectLists.filter(function(subitem, index) {
                    return item.uid != subitem.uid
                })
            }
        };
        // 搜索
        $scope.search = function() {
            var url;
            url = getParamUrl();
            // param.certificateType = $scope.certificateType || "";
            $scope.taskList = new PagingService(url + "?canAppointment=1", $scope.picker);
        };
        // 根据不同的id请求的列表地址会不同
        var getParamUrl = function() {
            var url, form_id;
            form_id = $routeParams.id;
            if (form_id == "hzj") {
                url = openApi.getAllCertificateA;
            } else if (form_id == "jzj") {
                url = openApi.getAllCertificate;
            } else if (form_id == "zjdp") {
                url = openApi.certificateShift;
            }
            return url;
        };
        // 获取数据返回
        $scope.submit = function() {
            // 缓存中的数据
            if ($scope.selectLists.length < 1) {
                Util.Toast("请选择");
                return;
            }
            localStorageService.set("selectLists", $scope.selectLists);
            Util.goBack();
        };
        // 过滤逻辑
        var hideDialog = function() {
            $scope.picker = angular.extend({}, relModuleObj.param || {});
            $rootScope.$emit('closemasker');
            $scope.showCerPicker = false;
        };
        $scope.cacelDialog = function() {
            hideDialog();
        };
        // 验证是否输入完整
        $scope.confirmDialog = function() {
            $scope.search()
            hideDialog();
        };
        $scope.$on('closemasker', function() {
            hideDialog()
        });
        var showDialog = function() {
            var param = {};
            param.type = "证件类别";
            Util.getcerTypeList(param, function(data) {
                $scope.resiTypeList = data.data
                $rootScope.$emit('showmasker');
                $scope.showCerPicker = true;

            });

        };

        $scope.searchID = function() {
            showDialog()
        }

        // 页面初始化请求数据
        var init = function() {
            $scope.search();
            $scope.selectLists = Util.getSelectLists();
        };
        init();
    });

