angular.module('jgappApp')
  .controller('ContractRktiketCtrl', function ($scope, $rootScope, DataService, openApi, Util, $location, $routeParams, FormSubmit) {
    var id = $scope.process_id = $routeParams.id
    $scope.choosePeople = function () {
      var relModuleObj = {
        selectTab: "project_money_select",
        selectTabContent: "工程名称"
      };
      // 将列表的数据序列化存入缓存以便回来时候使用
      Util.savaParamForReview($scope.param, id);
      Util.savaDataforsearch(relModuleObj);
      $location.path("finance/choosepeople")
    };
    $scope.chooseContract = function () {
      var relModuleObj = {
        selectTab: "select_common_contract",
        selectTabContent: "通用合同名称"
      };
      // 清掉关联的编号
      $scope.param.taxReceiptNo = "";
      Util.savaParamForReview($scope.param, id);
      Util.savaDataforsearch(relModuleObj);
      $location.path("finance/choosepeople")
    }
    // 选择报销单明细
    $scope.showCertificate = function () {
      $rootScope.$emit('showmasker');
      $scope.showCerPicker = true;
    };
    $scope.deletedItem = function (index) {
      $scope.param.details.splice(index, 1);
      $scope.index = -1;
    };
    $scope.addCertificate = function () {
      $scope.picker = $scope.picker || {};
      var check = false;
      check = checkPicker($scope.picker);
      if (!check) {
        return;
      };
      $scope.param.details.push($scope.picker);
      // 隐藏表单
      hideCertificate();
    };
    var hideCertificate = function () {
      $scope.picker = {};
      $rootScope.$emit('closemasker');
      $scope.showCerPicker = false;
    };
    $scope.$on('closemasker', function () {
      hideCertificate()
    });
    $scope.cacelCertificate = function () {
      hideCertificate();
    };
    // 验证是否输入完整
    var checkPicker = function (data) {
      var check = true;
      if (!data.name) {
        Util.Toast("请填写名称");
        check = false;
        return check;
      }
      if (!data.type) {
        Util.Toast("请填写规格/型号");
        check = false;
        return check;
      }
      if (!data.price) {
        Util.Toast("请填写单价");
        check = false;
        return check;
      }
      if (!data.quantity) {
        Util.Toast("请填写单据数量");
        check = false;
        return check;
      }
      if (!data.amount) {
        Util.Toast("请填写总价");
        check = false;
        return check;
      }
      return check;

    };
    $scope.swipe = function (index) {
      $scope.index = index;
    }
    $scope.resetlist = function (index) {
      $scope.index = -1;
    }
    $scope.submit = function (operationId) {
      $scope.param.entryDetails = angular.toJson($scope.param.details);
      // 底部类型end
      var options = {};
      // 流程id
      options.id = id;
      // 根据operationId判断是草稿还是提交
      options.operationId = operationId;
      options.urlParam = openApi.godownEntry;
      options.param = angular.copy($scope.param, {});
      delete options.param.details
      FormSubmit.submit(options,$scope);
    };
    $scope.validate = function () {
      if (!$scope.param.projectName) {
        Util.Toast("请选择工程类型");
        return;
      }
      if (!$scope.param.godown) {
        Util.Toast("请填写所入仓库");
        return;
      }
      if (!$scope.param.keeper) {
        Util.Toast("请填写库管员");
        return;
      }
      if (!$scope.param.receiver) {
        Util.Toast("请填写签收人");
        return;
      }
      if ($scope.param.details.length < 1) {
        Util.Toast("请填写报销明细");
        return;
      }
      if (!$scope.validation.passvalidation) {
        Util.Toast($scope.validation.tip);
        return;
      }
      return true;
    }
    var init = function () {
      // 获取回显的详细信息
      Util.getDetailData(id, function (data) {
        $scope.param = data;
        $scope.param.details = $scope.param.details || []
      });
    };
    // 初始化
    init();
  });

