/**
 * @ngdoc function
 * @name jgappApp.controller:AttendanceAttendanceLateCtrl
 * @description
 * # AttendanceAttendanceLateCtrl
 * Controller of the jgappApp
 */
angular.module('jgappApp')
    .controller('AttendanceAttendanceLateCtrl', function (DataService, openApi, $location,localStorageService, MapService, Util, $routeParams) {
        var vm = this;
        // 获取考勤详情
        var checkinfo = {};
        checkinfo = localStorageService.get("checkinfo");
        var ifPermission = false;
        this.tip = $routeParams.type == "early" ? "早退" : "迟到";
        this.atttip = "考勤成功";
        // 获取考勤数据
        vm.param = Util.getLocalInfo("attParam");
        vm.param.remark = ""
        this.submit = function () {
            if(checkinfo.clockWithSelfie==1&&!vm.param.attachment){
                Util.Toast("请在自拍后再打卡");
                return;
            }
            // 获取当前位置信息
            MapService.getcurPositon().then(function (data) {
                // 需要考勤位置
                var attPoint = {};
                attPoint.latitude = checkinfo.lat;
                attPoint.longitude = checkinfo.lng;
                var curPoint = data;
                vm.param.lat = curPoint.latitude;
                vm.param.lng = curPoint.longitude;
                vm.param.address = curPoint.address+curPoint.describe;
                // 如果外勤则跳转页面
                ifPermission = MapService.permissionDistance(attPoint, curPoint, checkinfo.offSet);
                var wifiSign = false;
                if (vm.param.wifiName) {
                    wifiSign = true
                } else if (ifPermission) {
                    wifiSign = true;
                }
                if (wifiSign) {
                    DataService.getData(openApi.punchClock, vm.param).then(function (data) {
                        if (data.code == 1) {
                            navigator.notification.beep(1);
                            Util.Toast(vm.atttip, {
                                callback: Util.goBack
                            });
                            Util.clearLocalInfo("attParam")
                        } else {
                            Util.Toast(data.result, {
                                callback: Util.goBack
                            });
                        }
                    })
                } else {
                    // 外勤，去到外勤页面
                    vm.param.logType = 0;
                    // 删除备注
                    delete vm.param.remark;
                    Util.saveLocalInfo("attParam", vm.param);
                    $location.path("attendance/attendance_outside").replace();
                }
            })
        }
    });

'use strict';

/**
 * @ngdoc function
 * @name jgappApp.controller:AttendanceAttendanceOutsideCtrl
 * @description
 * # AttendanceAttendanceOutsideCtrl
 * Controller of the jgappApp
 */
angular.module('jgappApp')
    .controller('AttendanceAttendanceOutsideCtrl', function (DataService, localStorageService, openApi, MapService, Util) {
        var vm = this;
        // 获取考勤详情
        var checkinfo = {};
        checkinfo = localStorageService.get("checkinfo");
        vm.param = Util.getLocalInfo("attParam");
        vm.type = "外勤";
        this.submit = function () {
            if (!vm.type) {
                Util.Toast("请选择外勤类型")
                return
            }

            // 获取当前位置信息
            MapService.getcurPositon().then(function (data) {
                var curPoint = data;
                var attPoint = {};
                attPoint.latitude = checkinfo.lat;
                attPoint.longitude = checkinfo.lng;
                vm.param.distance = MapService.getDistance(attPoint, curPoint);
                if (checkinfo.clockWithSelfie == 1 && !vm.param.attachment) {
                    Util.Toast("请在自拍后再打卡");
                    return;
                }

                // 重新获取地址
                vm.param.lat = curPoint.latitude;
                vm.param.lng = curPoint.longitude;
                vm.param.address = curPoint.address + curPoint.describe;
                vm.param.remark = "[" + vm.type + "]" + (vm.content ? vm.content : "")
                DataService.getData(openApi.punchClock, vm.param).then(function (data) {
                    if (data.code == 1) {
                        navigator.notification.beep(1);
                        Util.Toast("考勤成功", {
                            callback: Util.goBack
                        });
                        Util.clearLocalInfo("attParam")
                    } else {
                        Util.Toast(data.result);
                    }
                })
            })
        };

    });

