/**
 * @ngdoc function
 * @name jgappApp.controller:AttendanceAttendanceUserCtrl
 * @description
 * # AttendanceAttendanceUserCtrl
 * Controller of the jgappApp
 */
angular.module('jgappApp')
  .controller('AttendanceAttendanceUserCtrl', function (DataService,Util, $rootScope, openApi, localStorageService, $routeParams) {
    var vm = this;
    var attDetail = localStorageService.get("attDetail")||{};
    this.peoplelist = [];
    $rootScope.userArr = []
    this.handleUser = function (userObj) {
      if (userObj.selected) {
        userObj.flag = 1
        $rootScope.userArr.push(userObj)
      } else {
        userObj.flag = 0
        $rootScope.userArr = $rootScope.userArr.filter(function (item, index) {
          return item.id != userObj.id
        })
      }
      $rootScope.$broadcast("userArrchange")
    }
    var init = function () {
      var param = {};
      param.acId = $routeParams.id;
      DataService.getData(openApi.attSelectExclusionn, param).then(function (data) {
        vm.peoplelist = data
        data.forEach(function (item, index) {
          item.children.forEach(function (item, index) {
            // 设置选中状态
            if (item.flag == 1) {
              item.selected = true;
              $rootScope.userArr.push(item)
            }
          });
          $rootScope.$broadcast("userArrchange")
        })

      })
    }
    this.confirm = function () {
      attDetail.exclusionUsers = $rootScope.userArr.map(function(item,index){
        return item.id
      });
      localStorageService.set("attDetail", attDetail);
      $rootScope.userArr = [];
      Util.goBack();
    }
    init()
  });

'use strict';

/**
 * @ngdoc function
 * @name jgappApp.controller:AttendanceAttendanceDepsCtrl
 * @description
 * # AttendanceAttendanceDepsCtrl
 * Controller of the jgappApp
 */
angular.module('jgappApp')
    .controller('AttendanceAttendanceDepsCtrl', function(DataService, Util, openApi, localStorageService, $routeParams) {
        var vm = this;
        var attDetail = localStorageService.get("attDetail") || {};
        this.peoplelist = [];
        var userArr = []
        var init = function() {
            var param = {};
            param.acId = $routeParams.id;
            DataService.getData(openApi.attSelectdepartment, param).then(function(data) {
                vm.deplist = data;
                userArr = vm.deplist.forEach(function(item, index) {
                    if (item.name == 2||attDetail.department&&attDetail.department.indexOf(item.value)>-1) {
                        item.selected = true;
                    }
                })
                console.log(data)
            })
        }
        this.checkItem = function(disabled) {
            if (disabled == 1) {
                Util.Toast("当前部门已经在考勤当中");
            }
        };
        this.confirm = function() {
            userArr = vm.deplist.filter(function(item, index) {
                return item.selected;
            })
            attDetail.department = userArr.map(function(item, index) {
                return item.value
            })
            attDetail.departments = userArr.map(function(item, index) {
                return item.text
            }).toString();
            localStorageService.set("attDetail", attDetail);
            Util.goBack();
        }
        init()
    });
