/**
 * @ngdoc directive
 * @name myAppApp.directive:backBtn
 * @description
 * # backBtn
 */
angular.module('jgappApp')
    .directive('backBtn', function(Util) {
        return {
            scope: {
                fn: "=fn"
            },
            template: '<div class="backbtn">返回</div>',
            restrict: 'AE',
            replace: true,
            link: function postLink(scope, element, attrs) {
                // element.text('this is the backBtn directive');
                element.bind('click', function() {
                    if (attrs.cleancache != "no") {
                        Util.clearFormData();
                    }
                    var num = Util.getRelMoNum()
                    if (num) {
                        Util.setRelMoNum(0)
                    } else {
                        Util.clearTVType()
                    }
                    if (scope.fn) {
                        scope.fn();
                    } else {
                        Util.goBack();
                    }
                });
            }
        };
    }).directive("ngTouchstart", function() {
        return {
            controller: ["$scope", "$element", function($scope, $element) {

                $element.bind("touchstart", onTouchStart);

                function onTouchStart(event) {
                    var method = $element.attr("ng-touchstart");
                    $scope.$event = event;
                    $scope.$apply(method);
                }

            }]
        }
    })
    .directive("ngTouchmove", function() {
        return {
            controller: ["$scope", "$element", function($scope, $element) {

                $element.bind("touchstart", onTouchStart);

                function onTouchStart(event) {
                    event.preventDefault();
                    $element.bind("touchmove", onTouchMove);
                    $element.bind("touchend", onTouchEnd);
                }

                function onTouchMove(event) {
                    var method = $element.attr("ng-touchmove");
                    $scope.$event = event;
                    $scope.$apply(method);
                }

                function onTouchEnd(event) {
                    event.preventDefault();
                    $element.unbind("touchmove", onTouchMove);
                    $element.unbind("touchend", onTouchEnd);
                }

            }]
        }
    })
    .directive("ngTouchend", function() {
        return {
            controller: ["$scope", "$element", function($scope, $element) {

                $element.bind("touchend", onTouchEnd);

                function onTouchEnd(event) {
                    var method = $element.attr("ng-touchend");
                    $scope.$event = event;
                    $scope.$apply(method);
                }

            }]
        }
    });

"use strict";

/**
 * @ngdoc directive
 * @name jgappApp.directive:dateDirective
 * @description
 * # dateDirective
 */
angular.module("jgappApp").directive("dateDirective", [
  "$filter",
  function ($filter) {
    return {
      require: "ngModel",
      restrict: "AE",
      link: function (scope, element, attrs, ngModelController) {
        var type;
        var currYear = new Date().getFullYear();
        type = attrs.datetype || "date";
        var opt = {};
        opt.default = {
          display: "bottom", //显示方式
          mode: "scroller", //日期选择模式
          lang: "zh",
          dateFormat: "yy-mm-dd",
        };
        if (type == "date" || type == "datetime") {
          if (attrs.min) {
            opt.default.minDate = new Date(new Date());
          }
          opt.default.maxDate = new Date(new Date().setFullYear(currYear + 5));
          if (type == "date") {
            $(element[0]).mobiscroll(opt.default).date(opt.default);
          } else if (type == "datetime") {
            opt.default.timeFormat = "HH:ii:ss";
            $(element[0]).mobiscroll(opt.default).datetime(opt.default);
          }
        } else if (type == "time") {
          $(element[0]).mobiscroll(opt.default).time(opt.default);
        }
        ngModelController.$formatters.push(function (data) {
          //convert data from model format to view format
          var date;
          if (type == "datetime") {
            date = $filter("dateFmt")(data, "yyyy-MM-dd hh:mm:ss");
          } else if (type == "time") {
            // date = $filter("dateFmt")(data, "hh:mm")
            date = data;
          } else {
            date = $filter("dateFmt")(data);
          }
          return date; //converted
        });
      },
    };
  },
]);

