"use strict";

/**
 * @ngdoc directive
 * @name jgappApp.directive:Map
 * @description
 * # Map
 * This directive encapsulates the `baidu-map` component, allowing for a cleaner
 * integration into the application and providing a consistent interface.
 * It takes various map-related parameters and passes them directly to the
 * underlying `baidu-map` directive.
 */
angular.module("jgappApp").directive("map", function (MapService) {
  return {
    scope: {
      options: "=", // Input: options for the baidu-map, e.g., center, zoom
      onMapLoaded: "=", // Callback: fired when the baidu map is ready, exposing the map instance
      offline: "=", // Input: text to display when offline
      onMapClick: "=", // Callback: fired when the map is clicked
      ak: "=", // Input: Baidu Map Access Key
    },
    template: `<leaflet ng-if="center" markers="markers" center="center" width="100%" height="100%" tiles="tiles"></leaflet>`,
    restrict: "AE",
    link: function ($scope) {
      // 立即初始化 center，避免模板渲染时未定义
      $scope.center = {
        lat: 0, // 默认北京坐标
        lng: 0,
        zoom: 18,
      };

      $scope.tk = MapService.getAk();
      $scope.tiles = {
        url:
          "http://t0.tianditu.gov.cn/vec_w/wmts?SERVICE=WMTS&REQUEST=GetTile&VERSION=1.0.0&LAYER=vec&STYLE=default&TILEMATRIXSET=w&FORMAT=tiles&TILEMATRIX={z}&TILEROW={y}&TILECOL={x}&tk=" +
          $scope.tk,
      };
      $scope.$watch("options.markers", function (markers) {
        if (markers && markers.length > 0) {
          $scope.center = {
            lat: markers[0].latitude,
            lng: markers[0].longitude,
            zoom: 18,
          };
        }
      });
    },
  };
});

