/**
 * @ngdoc filter
 * @name jgappApp.filter:NBFmt
 * @function
 * @description
 * # NBFmt
 * Filter in the jgappApp.
 */
angular
  .module("jgappApp")
  .filter("NBFmt", function() {
    return function(input, n) {
      n = n > 0 && n <= 20 ? n : 2;
      if (input) {
        input =
          parseFloat((input + "").replace(/[^\d\.-]/g, "")).toFixed(n) + "";
        var l = input
            .split(".")[0]
            .split("")
            .reverse(),
          r = input.split(".")[1];
        var t = "";
        for (var i = 0; i < l.length; i++) {
          t += l[i] + ((i + 1) % 3 == 0 && i + 1 != l.length ? "," : "");
        }
        return (
          t
            .split("")
            .reverse()
            .join("") +
          "." +
          r
        );
      } else {
        return input;
      }
    };
  })
  .filter("countLimit", function() {
    return function(input) {
      if (input) {
        if (input > 99) {
          return "99+";
        }
        return input;
      }
    };
  })
  .filter("fileSize", function() {
    var formats = {
      Byte: Math.pow(10, 0),
      KB: Math.pow(10, 3),
      MB: Math.pow(10, 6),
      GB: Math.pow(10, 9),
      TB: Math.pow(10, 12),
      PB: Math.pow(10, 15),
      EB: Math.pow(10, 18),
      ZB: Math.pow(10, 21),
      YB: Math.pow(10, 24),
      BB: Math.pow(10, 27)
    };
    function formatFileSize(fileSize, lenght) {
      var r;
      var l = lenght || 2;
      for (var k in formats) {
        var v = formats[k];
        r = fileSize / v;
        if (r >= 1 && r < 1000) {
          r = parseInt(r * Math.pow(10, l), 10) / Math.pow(10, l) + k;
          break;
        }
      }
      return r;
    }
    return function(input) {
      if (input) {
        return formatFileSize(input);
      }
    };
  });

"use strict";

/**
 * @ngdoc filter
 * @name jgappApp.filter:fileName
 * @function
 * @description
 * # fileName
 * Filter in the jgappApp.
 */
angular
  .module("jgappApp")
  .filter("fileName", function() {
    return function(input) {
      if (input) {
        return input.slice(input.indexOf("_") + 1);
      }
    };
  })
  .filter("showimg", function(openApi) {
    return function(input) {
      if (input) {
        var signStr=NativeUtil.getSignStr()
        if(input.indexOf("http")==-1){
          return openApi.showimg + "?imgUrl=" + input + "&" +signStr;
        }
        return input+ "?" +signStr;
      }
    };
  })
  .filter("ifimg", function(openApi) {
    return function(input) {
      if (input) {
        return /(.+)\.(jpg|png|gif|jpeg)$/gi.test(input);
      }
    };
  })
  .filter("iffile", function(openApi) {
    return function(input) {
      if (input) {
        return /(.+)\.(docx|ppt|doc|xls|zip|rar|xlsx|et|pptx|pdf|wps|txt|pub)$/gi.test(
          input
        );
      }
    };
  })
  .filter("userinfo", function(localStorageService) {
    return function(input, key) {
      var data = localStorageService.get("ContactInfo");
      if (input && data) {
        var user={};
        data.some(function(item, index) {
          if (item.children) {
            var check = item.children.some(function(subitem, index) {
              user = subitem;
              return subitem.id == input;
            });
            return check;
          }
        });
        return user[key];
      } else {
        return input;
      }
    };
  })
  .filter("aduituserfilter", function() {
    return function(input) {
      var numberSymbols = [ '①', '②', '③', '④', '⑤', '⑥', '⑦', '⑧', '⑨', '⑩','⑪','⑫','⑬','⑭','⑮','⑯','⑰','⑱','⑲','⑳' ];
      function formatUsersContent (v) {
        if (v) {
          var str = '',symbols;
          v.split(',').forEach(function (item, index) {
            symbols = numberSymbols[index] || (index + 1);
            str = str + ' ' + symbols + item;
          });
          return  str;
      
        } else {
          return v;
        }
      }
      
      if (input) {        
        return  formatUsersContent(input);
      } else {
        return input;
      }
    };
  });
'use strict';

/**
 * @ngdoc filter
 * @name jgappApp.filter:dateFilter
 * @function
 * @description
 * # dateFilter
 * Filter in the jgappApp.
 */
angular.module('jgappApp')
    .filter('getDay', function () {
        return function (input) {
            if (input) {
                if (typeof input == "string") {
                    input = input.replace(/-/g, "/")
                }
                input = new Date(input)
                var weekday;
                switch (input.getDay()) {
                    case 1:
                        weekday = "一";
                        break;
                    case 2:
                        weekday = "二";
                        break;
                    case 3:
                        weekday = "三";
                        break;
                    case 4:
                        weekday = "四";
                        break;
                    case 5:
                        weekday = "五";
                        break;
                    case 6:
                        weekday = "六";
                        break;
                    case 0:
                        weekday = "天";
                        break;
                }
                return "星期" + weekday
            }
        };
    })
    .filter('timeFormat', function () {
        return function (time) {
            var date = "";
            if (typeof time != "undefined") {
                if (time < 10 && time >= 0) {
                    date = "0" + time
                } else {
                    date = date + time;
                }
            }
            return date;
        };
    })
    .filter('isCurDate', function ($filter) {
        return function (time, compare) {
            var isCurDate = false;
            if (typeof time != "undefined") {
                var date = new Date();
                if (typeof compare != "undefined") {
                    date = compare;
                }
                isCurDate = $filter("dateFmt")(time) == $filter("dateFmt")(date)
            }
            return isCurDate;
        };
    })
    .filter('dateFmt', function () {
        return function (date, fmt) {
            if (!date) {
                return
            }
            if (typeof date == "string") {
                date = date.replace(/-/g, "/")
            }
            date = new Date(date);
            fmt = fmt || "yyyy-MM-dd";
            var o = {
                "M+": date.getMonth() + 1, //月份 
                "d+": date.getDate(), //日 
                "h+": date.getHours(), //小时 
                "m+": date.getMinutes(), //分 
                "s+": date.getSeconds(), //秒 
                "q+": Math.floor((date.getMonth() + 3) / 3), //季度 
                "S": date.getMilliseconds() //毫秒 
            };
            if (/(y+)/.test(fmt)) fmt = fmt.replace(RegExp.$1, (date.getFullYear() + "").substr(4 - RegExp.$1.length));
            for (var k in o)
                if (new RegExp("(" + k + ")").test(fmt)) fmt = fmt.replace(RegExp.$1, (RegExp.$1.length == 1) ? (o[k]) : (("00" + o[k]).substr(("" + o[k]).length)));
            return fmt;
        };
    });
'use strict';

